// OAuth 2.0 Configuration
const OAUTH_CONFIG = {
  clientId: 'your-client-id',
  clientSecret: 'your-client-secret', // SECURITY RISK: See warning above
  authorizationEndpoint: 'https://auth.example.com/oauth/authorize',
  tokenEndpoint: 'https://auth.example.com/oauth/token',
  revocationEndpoint: 'https://auth.example.com/oauth/revoke',
  userInfoEndpoint: 'https://auth.example.com/oauth/userinfo',
  scopes: ['openid', 'profile', 'email', 'offline_access'],
  redirectUri: AuthSession.makeRedirectUri({
    scheme: 'myapp',
    path: 'oauth/callback',
  }),
};

// Storage keys
const STORAGE_KEYS = {
  ACCESS_TOKEN: '@oauth_access_token',
  REFRESH_TOKEN: '@oauth_refresh_token',
  TOKEN_EXPIRY: '@oauth_token_expiry',
  USER_INFO: '@oauth_user_info',
};

// Token refresh buffer (refresh 5 minutes before expiry)
const TOKEN_REFRESH_BUFFER_SECONDS = 300;

// --- Token Management Service ---
class TokenService {
  static async storeTokens(accessToken, refreshToken, expiresIn) {
    const expiryTime = Date.now() + expiresIn * 1000;
    await AsyncStorage.multiSet([
      [STORAGE_KEYS.ACCESS_TOKEN, accessToken],
      [STORAGE_KEYS.REFRESH_TOKEN, refreshToken || ''],
      [STORAGE_KEYS.TOKEN_EXPIRY, expiryTime.toString()],
    ]);
    return { accessToken, refreshToken, expiryTime };
  }

  static async getTokens() {
    const values = await AsyncStorage.multiGet([
      STORAGE_KEYS.ACCESS_TOKEN,
      STORAGE_KEYS.REFRESH_TOKEN,
      STORAGE_KEYS.TOKEN_EXPIRY,
    ]);
    const accessToken = values[0][1];
    const refreshToken = values[1][1];
    const expiryTime = values[2][1] ? parseInt(values[2][1], 10) : null;
    return { accessToken, refreshToken, expiryTime };
  }

  static async clearTokens() {
    await AsyncStorage.multiRemove([
      STORAGE_KEYS.ACCESS_TOKEN,
      STORAGE_KEYS.REFRESH_TOKEN,
      STORAGE_KEYS.TOKEN_EXPIRY,
      STORAGE_KEYS.USER_INFO,
    ]);
  }

  static isTokenExpired(expiryTime) {
    if (!expiryTime) return true;
    return Date.now() >= expiryTime - TOKEN_REFRESH_BUFFER_SECONDS * 1000;
  }

  static async exchangeCodeForTokens(code, codeVerifier) {
    const body = new URLSearchParams({
      grant_type: 'authorization_code',
      code,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      client_id: OAUTH_CONFIG.clientId,
      client_secret: OAUTH_CONFIG.clientSecret,
      ...(codeVerifier && { code_verifier: codeVerifier }),
    });

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(
        errorData.error_description || errorData.error || 'Token exchange failed'
      );
    }

    const tokenData = await response.json();
    return TokenService.storeTokens(
      tokenData.access_token,
      tokenData.refresh_token,
      tokenData.expires_in
    );
  }

  static async refreshAccessToken(refreshToken) {
    const body = new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: OAUTH_CONFIG.clientId,
      client_secret: OAUTH_CONFIG.clientSecret,
    });

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(
        errorData.error_description || errorData.error || 'Token refresh failed'
      );
    }

    const tokenData = await response.json();
    return TokenService.storeTokens(
      tokenData.access_token,
      tokenData.refresh_token || refreshToken,
      tokenData.expires_in
    );
  }

  static async revokeToken(token) {
    try {
      const body = new URLSearchParams({
        token,
        client_id: OAUTH_CONFIG.clientId,
        client_secret: OAUTH_CONFIG.clientSecret,
      });

      await fetch(OAUTH_CONFIG.revocationEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: body.toString(),
      });
    } catch (error) {
      console.warn('Token revocation failed:', error);
    }
  }

  static async getValidAccessToken() {
    const { accessToken, refreshToken, expiryTime } = await TokenService.getTokens();

    if (!accessToken) {
      throw new Error('No access token available');
    }

    if (!TokenService.isTokenExpired(expiryTime)) {
      return accessToken;
    }

    if (refreshToken) {
      try {
        const newTokens = await TokenService.refreshAccessToken(refreshToken);
        return newTokens.accessToken;
      } catch (error) {
        await TokenService.clearTokens();
        throw new Error('Session expired. Please log in again.');
      }
    }

    await TokenService.clearTokens();
    throw new Error('Session expired. Please log in again.');
  }

  static async fetchUserInfo(accessToken) {
    const response = await fetch(OAUTH_CONFIG.userInfoEndpoint, {
      headers: {
        Authorization: `Bearer ${accessToken}`,
      },
    });

    if (!response.ok) {
      throw new Error('Failed to fetch user info');
    }

    const userInfo = await response.json();
    await AsyncStorage.setItem(STORAGE_KEYS.USER_INFO, JSON.stringify(userInfo));
    return userInfo;
  }
}

// --- Authenticated API Client ---
class ApiClient {
  static async request(url, options = {}) {
    const accessToken = await TokenService.getValidAccessToken();

    const response = await fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        Authorization: `Bearer ${accessToken}`,
        'Content-Type': 'application/json',
      },
    });

    // If we get a 401, try refreshing the token once
    if (response.status === 401) {
      const { refreshToken } = await TokenService.getTokens();
      if (refreshToken) {
        try {
          const newTokens = await TokenService.refreshAccessToken(refreshToken);
          const retryResponse = await fetch(url, {
            ...options,
            headers: {
              ...options.headers,
              Authorization: `Bearer ${newTokens.accessToken}`,
              'Content-Type': 'application/json',
            },
          });
          return retryResponse;
        } catch (refreshError) {
          await TokenService.clearTokens();
          throw new Error('Session expired. Please log in again.');
        }
      }
    }

    return response;
  }
}

// --- Custom Hook for OAuth ---
function useOAuth() {
  const [state, setState] = useState({
    isLoading: true,
    isAuthenticated: false,
    user: null,
    error: null,
  });

  const refreshTimerRef = useRef(null);

  const discovery = {
    authorizationEndpoint: OAUTH_CONFIG.authorizationEndpoint,
    tokenEndpoint: OAUTH_CONFIG.tokenEndpoint,
    revocationEndpoint: OAUTH_CONFIG.revocationEndpoint,
  };

  const [request, response, promptAsync] = AuthSession.useAuthRequest(
    {
      clientId: OAUTH_CONFIG.clientId,
      scopes: OAUTH_CONFIG.scopes,
      redirectUri: OAUTH_CONFIG.redirectUri,
      responseType: AuthSession.ResponseType.Code,
      usePKCE: true,
      extraParams: {
        access_type: 'offline',
        prompt: 'consent',
      },
    },
    discovery
  );

  // Schedule automatic token refresh
  const scheduleTokenRefresh = useCallback((expiryTime) => {
    if (refreshTimerRef.current) {
      clearTimeout(refreshTimerRef.current);
    }

    const timeUntilRefresh =
      expiryTime - Date.now() - TOKEN_REFRESH_BUFFER_SECONDS * 1000;

    if (timeUntilRefresh > 0) {
      refreshTimerRef.current = setTimeout(async () => {
        try {
          const { refreshToken } = await TokenService.getTokens();
          if (refreshToken) {
            const newTokens = await TokenService.refreshAccessToken(refreshToken);
            console.log('Token automatically refreshed');
            scheduleTokenRefresh(newTokens.expiryTime);
          }
        } catch (error) {
          console.error('Auto token refresh failed:', error);
          setState((prev) => ({
            ...prev,
            isAuthenticated: false,
            user: null,
            error: 'Session expired. Please log in again.',
          }));
        }
      }, timeUntilRefresh);
    }
  }, []);

  // Check for existing session on mount
  useEffect(() => {
    const checkExistingSession = async () => {
      try {
        const { accessToken, refreshToken, expiryTime } =
          await TokenService.getTokens();

        if (!accessToken) {
          setState({ isLoading: false, isAuthenticated: false, user: null, error: null });
          return;
        }

        if (TokenService.isTokenExpired(expiryTime) && refreshToken) {
          const newTokens = await TokenService.refreshAccessToken(refreshToken);
          const userInfo = await TokenService.fetchUserInfo(newTokens.accessToken);
          scheduleTokenRefresh(newTokens.expiryTime);
          setState({
            isLoading: false,
            isAuthenticated: true,
            user: userInfo,
            error: null,
          });
        } else if (!TokenService.isTokenExpired(expiryTime)) {
          const cachedUser = await AsyncStorage.getItem(STORAGE_KEYS.USER_INFO);
          const userInfo = cachedUser
            ? JSON.parse(cachedUser)
            : await TokenService.fetchUserInfo(accessToken);
          scheduleTokenRefresh(expiryTime);
          setState({
            isLoading: false,
            isAuthenticated: true,
            user: userInfo,
            error: null,
          });
        } else {
          await TokenService.clearTokens();
          setState({
            isLoading: false,
            isAuthenticated: false,
            user: null,
            error: null,
          });
        }
      } catch (error) {
        console.error('Session check failed:', error);
        await TokenService.clearTokens();
        setState({
          isLoading: false,
          isAuthenticated: false,
          user: null,
          error: null,
        });
      }
    };

    checkExistingSession();

    return () => {
      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }
    };
  }, [scheduleTokenRefresh]);

  // Handle auth response
  useEffect(() => {
    const handleResponse = async () => {
      if (response?.type === 'success') {
        const { code } = response.params;
        try {
          setState((prev) => ({ ...prev, isLoading: true, error: null }));

          const tokens = await TokenService.exchangeCodeForTokens(
            code,
            request?.codeVerifier
          );
          const userInfo = await TokenService.fetchUserInfo(tokens.accessToken);
          scheduleTokenRefresh(tokens.expiryTime);

          setState({
            isLoading: false,
            isAuthenticated: true,
            user: userInfo,
            error: null,
          });
        } catch (error) {
          console.error('Token exchange failed:', error);
          setState({
            isLoading: false,
            isAuthenticated: false,
            user: null,
            error: error.message,
          });
        }
      } else if (response?.type === 'error') {
        setState((prev) => ({
          ...prev,
          isLoading: false,
          error: response.error?.message || 'Authentication failed',
        }));
      } else if (response?.type === 'dismiss') {
        setState((prev) => ({
          ...prev,
          isLoading: false,
        }));
      }
    };

    handleResponse();
  }, [response, request, scheduleTokenRefresh]);

  const login = useCallback(async () => {
    setState((prev) => ({ ...prev, error: null }));
    await promptAsync();
  }, [promptAsync]);

  const logout = useCallback(async () => {
    try {
      setState((prev) => ({ ...prev, isLoading: true }));

      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }

      const { accessToken, refreshToken } = await TokenService.getTokens();

      if (refreshToken) {
        await TokenService.revokeToken(refreshToken);
      }
      if (accessToken) {
        await TokenService.revokeToken(accessToken);
      }

      await TokenService.clearTokens();

      setState({
        isLoading: false,
        isAuthenticated: false,
        user: null,
        error: null,
      });
    } catch (error) {
      console.error('Logout error:', error);
      await TokenService.clearTokens();
      setState({
        isLoading: false,
        isAuthenticated: false,
        user: null,
        error: null,
      });
    }
  }, []);

  return {
    ...state,
    login,
    logout,
    request,
  };
}

